        if (isValidCode && isValidBusiness && isActive) {
            validCodes.push_back(code[i]);
        }
    }

    // Sort by business line order and then by code lexicographically
    std::sort(validCodes.begin(), validCodes.end(), [&](const std::string& a, const std::string& b) {
        // Find the index of the business line for each code
        size_t idxA = std::find(businessOrder.begin(), businessOrder.end(), businessLine[std::find(code.begin(), code.end(), a) - code.begin()]);
        size_t idxB = std::find(businessOrder.begin(), businessOrder.end(), businessLine[std::find(code.begin(), code.end(), b) - code.begin()]);

        // Compare based on business line order
        if (idxA != idxB) {
            return idxA < idxB;
        }
        // If business line is the same, compare lexicographically
        return a < b;
    });

    return validCodes;
}

